import {
  createBrowserRouter,
  Outlet,
  redirect,
  RouterProvider,
} from "react-router-dom";

import { useEffect, useRef, useState } from "react";
import Layout from "./components/Layout/Layout";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import AppContainer from "./pages/AppContainer/AppContainer";
import Friends from "./pages/Friends/Friends";

function App() {
  const [token, setToken] = useState(null);
  const [isAuth, setIsAuth] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userId, setUserId] = useState(null);
  const ws = useRef(null);

  useEffect(() => {
    console.log("APP RUNNING");
    const token = localStorage.getItem("token");
    const expiryDate = localStorage.getItem("expiryDate");
    const userId = localStorage.getItem("userId");

    if (!token || !expiryDate) {
      setIsLoading(false);
      return;
    }

    if (new Date(expiryDate) <= new Date()) {
      setIsLoading(false);
      logoutHandler();
      return;
    }

    const checkTokenValidity = async () => {
      const res = await fetch("/auth/token", {
        method: "POST",
        headers: {
          Authorization: "Bearer " + token,
        },
      });

      if (res.status !== 200) {
        logoutHandler();
        return;
      }
      setToken(token);
      setUserId(userId);
      setIsAuth(true);
      setIsLoading(false);
    };

    checkTokenValidity();

    if (isAuth) {
      ws.current = new WebSocket(`ws://localhost:8080/?userId=${userId}`);

      ws.current.onopen = () => {
        console.log("Connection Opened");
        const data = {
          message: "Hello Server",
          userId: userId,
        };
        ws.current.send(JSON.stringify(data));
      };

      ws.current.onmessage = (message) => {
        console.log(message);
        console.log(message.data);
        try {
          let data = JSON.parse(message.data);
        } catch (err) {
          console.log(err);
        }
      };

      ws.current.onclose = () => {
        console.log("Connection Closed");
      };
      ws.current.onerror = () => {};
    }

    // Cleanup function
    return () => {
      if (ws.current) {
        ws.current.close();
      }
    };
  }, [isAuth]);

  const sendMessageHandler = (data) => {
    ws.current.send(JSON.stringify(data));
  };

  const logoutHandler = () => {
    setIsAuth(false);
    setToken(null);
    localStorage.removeItem("token");
    localStorage.removeItem("expiryDate");
    localStorage.removeItem("userId");
  };

  const loginHandler = async (formData) => {
    const data = { email: formData.email, password: formData.password };

    const res = await fetch("/auth/login", {
      method: "POST",
      body: JSON.stringify(data),
      headers: { "Content-Type": "application/json" },
    });

    let resData = await res.json();

    if (!resData.errors) {
      const remainingTimeMs = 7 * 24 * 60 * 60 * 1000; // 7 days
      const expiryDate = new Date(new Date().getTime() + remainingTimeMs);
      localStorage.setItem("expiryDate", expiryDate.toISOString());
      localStorage.setItem("token", resData.token);
      localStorage.setItem("userId", resData.userId);
      setToken(resData.token);
      setUserId(resData.userId);
      setIsAuth(true);
    }

    return resData;
  };

  const registerHandler = async (formData) => {
    const data = {
      email: formData.email,
      password: formData.password,
      username: formData.username,
    };

    const res = await fetch("/auth/register", {
      method: "POST",
      body: JSON.stringify(data),
      headers: { "Content-Type": "application/json" },
    });

    let resData = await res.json();
    return resData;
  };

  const router = createBrowserRouter([
    {
      path: "/",
      loader: () => {
        if (!isAuth && !isLoading) return redirect("/login");
        return null;
      },
      element: (
        <AppContainer token={token} logoutHandler={logoutHandler}>
          <Outlet></Outlet>
        </AppContainer>
      ),
      children: [
        {
          path: "/",
          element: <Friends></Friends>,
        },

        {
          path: "/friends",
          element: <Friends></Friends>,
        },
        {
          path: "/:id",
          element: (
            <Chat
              token={token}
              sendMessageHandler={sendMessageHandler}
              userId={userId}
            ></Chat>
          ),
        },
      ],
    },
    {
      path: "/",
      loader: () => {
        if (isAuth && !isLoading) return redirect("/");
        return null;
      },
      element: (
        <Layout>
          <Outlet></Outlet>
        </Layout>
      ),
      children: [
        {
          path: "/login",
          element: <Login loginHandler={loginHandler} />,
        },
        {
          path: "/register",
          element: (
            <Register
              registerHandler={registerHandler}
              loginHandler={loginHandler}
            />
          ),
        },
      ],
    },
  ]);

  if (isLoading) {
    return;
  }

  return <RouterProvider router={router}></RouterProvider>;
}

export default App;
